package inequivalent;

import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.assertTrue;

class ClonePair2909Method2Test {

    private final ClonePair2909 subject = new ClonePair2909();

    @Test
    void method2RecognizesValidId3Header() {
        // Generated by Codex (gpt-5.4).
        byte[] head = {'I', 'D', '3', 4, 0, 0, 0, 1, 2, 3};

        assertTrue(subject.method2(head));
    }

    @Test
    void method2RejectsWrongLengthHeaderBytesOrSyncsafeBytes() {
        // Generated by Codex (gpt-5.4).
        assertFalse(subject.method2(new byte[9]));

        byte[] wrongHeader = {'I', 'D', '2', 4, 0, 0, 0, 1, 2, 3};
        assertFalse(subject.method2(wrongHeader));

        byte[] invalidSyncsafe = {'I', 'D', '3', 4, 0, 0, (byte) 0x80, 1, 2, 3};
        assertFalse(subject.method2(invalidSyncsafe));
    }

    @Test
    void method2ThrowsNullPointerExceptionForNullInput() {
        // Generated by Codex (gpt-5.4).
        assertThrows(NullPointerException.class, () -> subject.method2(null));
    }
}
